INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027e88e3c98b0941765c1f', '酒店前台给升级了套房，体验非常好。早餐区有景观瀑布，酒店环境好，地理位置方便。适合商务出行，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0234g12000ck86vzh6ADB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000ck88an0DD57_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000ck8am7j2B5E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-13', '花园大床房', '大床房', '商务出差', 53, 0, 43, 6, '["整体满意度","前台服务","周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套'),
('68027e88e3c98b0941765c20', '第二次在携程订的，房间很大，设施都很好，一楼早餐人很多，要排队，二楼早餐品类少些也够吃，但是人少
用劵买了晚餐，不知道是不是人多，味道跟上次比有所下降，但是工作人员的还是一样的nice，很热情', '["https://dimg04.c-ctrip.com/images/0232h12000bzpmo8j966E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000bzpzuqz68E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000bzpv72y8BF6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000bzpy9lq7904_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000bzq0p2oDF5C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-24', '红棉大床套房', '套房', '情侣出游', 96, 0, 25, 7, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('68027e88e3c98b0941765c21', '老牌五星酒店整体不失水准，保持着自己的特色，及五星酒店该有的标准，值得推荐！大气宽敞的大堂，酒店前台有序高效的办理入住，全程笑容满面，非常nice!礼宾部的服务人员也很不错哦????酒店内（除房间）随处可见的花艺展示是酒店的一大亮点，入住时前台妹妹提供的酒店内景打卡，还不错，可以逛逛拍拍，酒店内的后花园虽小，却不影响她的特色。大堂吧有时间可以去坐坐，面包和咖啡?不错????
建议酒店房间内的卫生间，特别是冲凉房的设计，最好改善提升一下，太局促不方便，拉低了酒店整体满意度。房间内空调静音效果不错，花洒??水压足，好多五星酒店上述两点都不咋样。早餐品种少了点，希望以后能有改变。
整体不错！', '["https://dimg04.c-ctrip.com/images/0233712000byj9s9u3182_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000byjbzelB37E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000byj7a0wECE8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000byizzuj6CA3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000byja5317414_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000byj8egh4E39_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-08-20', '花园双床房', '双床房', '家庭亲子', 296, 2, 4, 8, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027e88e3c98b0941765c22', '老牌五星级酒店', '["https://dimg04.c-ctrip.com/images/0236m12000d2pb5di11E2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-29', '城央绿意双床房', '双床房', '家庭亲子', 7, 0, 1, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027e88e3c98b0941765c23', '非常棒，非常适合宅酒店，有很多打卡点，小朋友们很开心，很人性化，送了非常棒的一盒月饼，完美体验。不足点是客房充电插头不够用，等了两次。', '["https://dimg04.c-ctrip.com/images/0231012000cb7wdftBF4A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000cb7wt0s1874_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000cb7xz23F83A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-02', '花园双床房', '双床房', '家庭亲子', 67, 0, 5, 7, '["整体满意度","房间设施","客房服务"]'::jsonb, '整体满意度', '房间设施', '客房服务'),
('68027e94e3c98b0941765c24', '节日气氛浓厚，服务热情周到，感谢Ann为我们升级了房间，安静舒适，住宿体验很好！', '["https://dimg04.c-ctrip.com/images/0231q12000d6fq40h1CE5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000d6fs4xqA4FD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '红棉大床套房', '套房', '家庭亲子', 40, 0, 4, 7, '["整体满意度","前台服务","安静程度"]'::jsonb, '整体满意度', '前台服务', '安静程度'),
('68027e94e3c98b0941765c25', '来广州旅行，花园酒店是一个非常好的选择。酒店在市中心，有地铁可以直接到。淘金站上来就是。大堂非常气派。服务非常周到。客房干净，服务人员热情。里面有很多外国人。二楼的早餐非常好吃。每天都有更新。总体来说非常满意！', '["https://dimg04.c-ctrip.com/images/0230312000bts6cjd8EDD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000btryuo06FD5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000bts0sisBD25_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000bts5gqp88F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000bts4l6rE5F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000bts3ebs619B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000bts5s752B1B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000btrx3vd7D5F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000btrzoc72BDD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-04', '红棉双床套房', '套房', '家庭亲子', 105, 3, 8, 7, '["整体满意度","交通便利性","餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施'),
('68027e94e3c98b0941765c26', '花园酒店非常惊艳，是全家广州行觉得性价比最高的选择。首先是酒店的环境大气又有历史沉淀，然后是餐厅，酒店里面有几家米其林，早餐的两家餐厅都非常惊艳。难得的是酒店不但适合商务入住还适合亲子旅游，周边交通方便，商场和美食也不少。孩子最喜欢的就是去后花园喂小鱼了，唯一可惜的是露天泳池没有开放。', '["https://dimg04.c-ctrip.com/images/0230c12000bxqdopw889E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000bxqesqs5E4A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000bxqjo1yAAFB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000bxqeuw09816_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-17', '花园双床房', '双床房', '家庭亲子', 143, 0, 2, 9, '["性价比","餐饮设施","交通便利性"]'::jsonb, '性价比', '餐饮设施', '交通便利性'),
('68027e94e3c98b0941765c27', '房间非常满意，前台亲切，给我感觉特别好，一进大堂确实给我很震惊，富丽堂皇，面积如此之大，还有演出和弹琴～房间和早餐都很有广州特色～', '["https://dimg04.c-ctrip.com/images/0231a12000cc5x7iy8353_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000cc5uhbb7D2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000cc5uhbd583A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000cc5v1kz6212_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-06', '花园大床房', '大床房', '商务出差', 65, 0, 5, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027e94e3c98b0941765c28', '慕瀑布餐厅名而来，有更多惊喜。老派酒店新式装修设施齐全服务细致。泳池赞。自助晚餐的牛扒和甜品很正！芝士蛋糕好吃！还看了个小画展。', '["https://dimg04.c-ctrip.com/images/0235912000cci24mz48F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000cci09l13B1F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000cchyw0pB85D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000cci3nijF9AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000cci4fgy72AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-07', '花园大床房', '大床房', '独自旅行', 64, 0, 4, 7, '["餐饮设施","公共设施","整体满意度"]'::jsonb, '餐饮设施', '公共设施', '整体满意度'),
('68027e94e3c98b0941765c29', '首先说第一印象
1.服务:所有工作人员都很热情耐心友好，说真的特别温暖！第一晚的房间厕所反味，和大堂的bobo说了，立马给安排成了套房还送了小点心和一张手写信！服务方面真的无可挑剔！
2.设施:大堂很大，富丽堂皇的感觉，配套有棋牌室，壁球室，健身室，网球场，按摩室，桑拿浴室，室外游泳池，SPA（都没去，就看到室外泳池一直在维护无法使用）
3.儿童:
前台办理入住的时候，看到有带小孩就有工作人员上来发酒店自己做的黄油曲奇，和蔓越莓曲奇！yummy
	
还可以在前台领打卡的卡片，集满3个章就可以换一张书签，对于小朋友也很有趣啦，也可以顺便深度逛一逛酒店！
	
酒店内有花园酒店博物馆，周一闭馆，可以带娃去逛逛（也是一个集章打卡点）
4.房间:相对紧凑，没那么宽敞！
5.交通:酒店出门就是地铁站??出行便利，要坐APM线需要换乘相对麻烦点。
6.吃饭:酒店附近200m内就有广州酒家，点都德！走路就能到!花园酒店的早茶和瀑布餐厅也很有名
7.国际化:在花园酒店这几天真的是3步一个外国人，非常international了，酒店周围也全是外国人！工作人员想必外语肯定各个都很赞！
8.周边:第二天妹妹生病了，导航到周围几百米有一家医院，过去没有儿科，又打车过去中山大学附属第一医院，去医院也不远！能酒店深度评价到周边医院，多夸了我的好大儿
	花园酒店一共住了2晚，真的能感受到广州人民的热情专业温暖的服务！', '["https://dimg04.c-ctrip.com/images/0234u12000byi4cu60BA4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000byi16oxB0B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000byhr4us9780_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000byi4mzdFA14_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-20', '花园双床房', '双床房', '家庭亲子', 603, 0, 1, 9, '["前台服务","公共设施","交通便利性"]'::jsonb, '前台服务', '公共设施', '交通便利性'),
('68027e94e3c98b0941765c2a', '其实家就在附近，想临时抛开家里孩子谈谈恋爱。其实之前家里有亲戚之类的过来广州玩也会选择花园酒店。但是这回住又有新体验。前台的billy服务非常热情满脸笑容。为我们安排了可以吸烟的房型并做了升级。非常详细的介绍了房间是新装修过望花园瀑布，以及行政礼遇和设施。非常感动！装修后的花园酒店方方面面都符合五星级标准', '["https://dimg04.c-ctrip.com/images/0234i12000ccqa1nh68AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000ccq9cs309D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000ccqeipo6E20_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000ccqe6eyF5A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000ccqbo2m56B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000ccqbkdjE34D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000ccqb0qo8169_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000ccqchj74159_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000ccqa7xs408E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-08', '红棉大床套房', '套房', '情侣出游', 153, 0, 33, 8, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68027e94e3c98b0941765c2b', '房间设计西式化，估计当年是跟中国大酒店各不同风格，一个中式一个西式。吃早餐也是分中西式两个厅。服务生态度非常亲和，吃早餐虽然要排队等候，但是就算是一个人也可以选择坐一张桌子不与别人share，还会特意写上“留坐”示意。非常人性化。酒店很华丽！没住过的可以去感受一下。中餐厅也很有氛围。', '["https://dimg04.c-ctrip.com/images/0230812000bwjgd2b0592_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000bwjcjk37D0A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000bwjdkutF45F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-08-13', '花园大床房', '大床房', '其他', 142, 0, 9, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027e94e3c98b0941765c2c', '体验感最差的一次酒店入住，看乌鸦行为的视频被媒来的，视频里酒店设施看起来还挺好的，结果入住后发现设施陈旧，房间狭小，晚上洗个澡，水就从洗澡间里漏出来了，而且不是一点点，联系客房服务给换了一间房，感觉还是有点渗，只是没那么严重，忍了，窗台上是黑灰色的都是泥灰尘留下的痕迹，团购还一千五一晚的房费就这个样子，真心上当受骗，房间差成这样我又何必再在这个酒店多花一个子。', '["https://dimg04.c-ctrip.com/images/0233612000bwqm6bnF289_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000bwqk05l2146_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000bwqksflD0EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000bwqjmh8552D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-08-14', '花园双床房', '双床房', '家庭亲子', 181, 4, 7, 9, '["房间设施","卫生状况","性价比"]'::jsonb, '房间设施', '卫生状况', '性价比'),
('68027e94e3c98b0941765c2d', '环境挺好 拍照也挺出片的 服务态度也不错 吃的东西就那样吧 酒店的餐大同小异 人造瀑布还挺好看的 还有博物馆啥玩意儿的 前台的金箔纸红楼梦场景画很大气……', '["https://dimg04.c-ctrip.com/images/0236t12000c4kt4kaC21F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000c4l0b3m4CD1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000c4kx2xl5D2B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-09-13', '花园大床房', '大床房', '家庭亲子', 77, 0, 3, 6, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027e9ee3c98b0941765c2e', '房间真的还是挺不错的，很宽敞，装修也很新。特别是前台服务和客房服务都是满分，晚上口渴，就让服务多送5瓶水过来，也是很快满足！退房也是超级迅速！！下次还会住花园！', '["https://dimg04.c-ctrip.com/images/0204w12000c3wg2rn7BB7_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0235212000c3wfoaz6B60_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000c3wd68e6B43_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000c3wb9a17015_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-11', '红棉双床套房', '套房', '朋友出游', 80, 0, 4, 8, '["前台服务","客房服务","退房/入住效率"]'::jsonb, '前台服务', '客房服务', '退房/入住效率'),
('68027e9ee3c98b0941765c2f', '选的花园酒店作为接亲出门酒店
交通方便 也有好多外景可以出片
但是酒店房间还是旧了一点
不过整体适合敬茶接亲', '["https://dimg04.c-ctrip.com/images/0236812000cottxeo9EE4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000cottue72492_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000cou1lym88FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000cotrpt87F94_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000cou1qvc9C68_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000cou058eFFDE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-12-06', '红棉大床套房', '套房', '其他', 54, 0, 4, 6, '["交通便利性","房间设施","整体满意度"]'::jsonb, '交通便利性', '房间设施', '整体满意度'),
('68027e9ee3c98b0941765c30', '升级的房间十分满意，早餐一如既往的赞??前台接待处，客房处，用餐区的服务小组的服务意识都不错??本次体验挺满意～', '["https://dimg04.c-ctrip.com/images/0234g12000cf4f99g0C79_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-19', '花园双床房', '双床房', '家庭亲子', 56, 0, 2, 6, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027e9ee3c98b0941765c31', '特地挑选春节入住花园酒店，感受在花园酒店过除夕，体验很棒，热闹而温馨。特别感谢Ann，非常体贴细心，宾至如归。', '["https://dimg04.c-ctrip.com/images/0205v12000d67krbnE79A_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0231112000d66zau74517_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000d6751co74AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000d67iknsACB0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000d6755m63F47_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000d67b4zgFF6F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000d675q2b798E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-10', '花园大床房', '大床房', '独自旅行', 55, 0, 6, 7, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027e9ee3c98b0941765c32', '带娃出游，准备退房的时候，小宝宝闹觉，要睡觉，跟前台说明理由后，小姐姐延迟让我们退房，让宝宝睡一会！这点很窝心，服务很好！', '["https://dimg04.c-ctrip.com/images/0232y12000ccb3zyjB4D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000ccb3qw0C7F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000ccb3qw25D41_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-06', '花园双床房', '双床房', '家庭亲子', 61, 0, 6, 7, '["前台服务","退房/入住效率"]'::jsonb, '前台服务', '退房/入住效率', NULL),
('68027e9ee3c98b0941765c33', '第一次住花园酒店，老牌的酒店了，无论交通，酒店设施都很方便齐备。', '["https://dimg04.c-ctrip.com/images/0236912000cmzgvcm1817_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000cmzivu9F016_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000cmzlg0n4D15_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000cmzhk7s25A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-26', '花园大床房', '大床房', '其他', 32, 0, 30, 5, '["交通便利性","房间设施","公共设施"]'::jsonb, '交通便利性', '房间设施', '公共设施'),
('68027e9ee3c98b0941765c34', '我很高兴能够分享我对入住广州花园酒店体验，非常令人满意。花园酒店作为广州的一家知名五星级酒店，在服务和设施方面都非常出色。入住体验非常愉快，让我感受到了高品质的服务和舒适的环境。

首先，我非常欣赏酒店的设计和装修。房间宽敞明亮，设施齐全，而且非常干净整洁。床铺舒适，让我每天都能够得到充分的休息。浴室设施完善，包括高品质的洗浴用品和浴袍等，让我感到非常舒适。

其次，我非常满意酒店的服务。员工都非常友好和专业，能够满足我所有的需求。他们始终保持微笑，让人感到非常亲切。此外，酒店还提供了许多额外的服务，例如早餐、下午茶和晚间鸡尾酒等，这些服务都非常出色。

在性价比方面，我认为花园酒店的价格非常合理。虽然价格稍高，但考虑到酒店的高品质服务和设施，我认为这笔钱花得非常值得。如果你正在寻找一家高品质的酒店，我认为花园酒店是一个非常好的选择。

总的来说，我对“入住广州花园酒店体验”的评价非常高。酒店的服务和设施都非常好，让我感到非常舒适和满意。如果你正在计划来广州旅游，我强烈推荐你选择花园酒店作为你的住宿地点。总之，这是一次非常愉快的购物体验，我非常满意。', '["https://dimg04.c-ctrip.com/images/0234812000c880ow4A3A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000c885i30FC8F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000c886rx3A008_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000c882ure8C12_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232m12000c883ckg2120_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000c886e1s61BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-09-24', '花园大床房', '大床房', '朋友出游', 482, 0, 73, 9, '["整体满意度","房间设施","性价比"]'::jsonb, '整体满意度', '房间设施', '性价比'),
('68027e9ee3c98b0941765c35', '广州最早的五星酒店之一，艺术底蕴深厚，酒店位置很好，周围吃逛都很方便，虽然房间设施稍为老旧，但暇不掩瑜，服务和环境都很不错，下次来广州还会入住，值得推荐。', '["https://dimg04.c-ctrip.com/images/0234912000c46nsq3E433_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000c46qx1p99E6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000c46n2hsFF8F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000c46p35g6EA2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000c46ly9g20AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000c46q5t01D2E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-12', '红棉双床套房', '套房', '家庭亲子', 77, 0, 75, 8, '["整体满意度","周边配套","房间设施"]'::jsonb, '整体满意度', '周边配套', '房间设施'),
('68027e9ee3c98b0941765c36', '这次带崽崽来广州玩，选择花园酒店简直不要太明智，酒店有自己的历史，也有庭院可以散步游玩，对于10岁的孩子来说，酒店博物馆真的不错，非常推荐。另外，这是小朋友第一次独自完成check in，特别表扬前台的Viria and Ariel两位小姐姐，对小朋友特别耐心，漂亮又热情！', '["https://dimg04.c-ctrip.com/images/0235b12000bw7t6el0362_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000bw7kj6a04AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000bw7umy9D114_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-12', '花园双床房', '双床房', '家庭亲子', 137, 0, 6, 8, '["前台服务","整体满意度","公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施'),
('68027e9ee3c98b0941765c37', '挺开心的一次体验', '["https://dimg04.c-ctrip.com/images/0235012000dduh3gg3A20_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-03-11', '花园大床房', '大床房', '情侣出游', 8, 0, 1, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027ea9e3c98b0941765c38', '设施：说是三十年的酒店了，但是一点看出来 设施都很新

卫生：卫生更是没话说，酒店的每一处都很干净

环境：特别赞，酒店里面还有瀑布，

服务：帮我免费升房了，前台还送了花花 很贴心', '["https://dimg04.c-ctrip.com/images/0232112000bze7jbt1BBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000bze4nb5F605_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000bze2erhE95B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-23', '花园双床房', '双床房', '情侣出游', 91, 0, 5, 8, '["房间设施","卫生状况","前台服务"]'::jsonb, '房间设施', '卫生状况', '前台服务'),
('68027ea9e3c98b0941765c39', '环境非常好?? 服务也很周到 缺什么什么送来的也很快 自助早餐最爱 瀑布餐厅！房间非常大很舒适??一出地铁站就到门口了 比较可惜的就是游泳池在维修 希望下次去的时候能去游泳！', '["https://dimg04.c-ctrip.com/images/0231b12000c0k4dsn5747_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000c0k4dsp4746_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000c0k6qzw8FB3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000c0k3sy9D6A8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000c0k7pctA518_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-27', '红棉大床套房', '套房', '朋友出游', 87, 0, 1, 8, '["交通便利性","餐饮设施","整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度'),
('68027ea9e3c98b0941765c3a', '服务：大堂的巴基斯坦帅哥工作很认真，沟通非常好。
卫生：干净整洁
环境：旁边工地打桩到10点左右会停工。感觉吵闹可以去对面世贸，友谊转转，吃点东西，再回来。
设施：还行吧，浴盆的位置有点怪。卫生间和卧室通透，会有点气味传过来。先到外边的房间等10分钟再去卧室就没有气味。', '["https://dimg04.c-ctrip.com/images/0231812000bugwwjgBF43_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000bugyszmD570_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000buh2fz75126_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000buh0qrw9175_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000buh0h32129C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000buh3xeeF987_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000bugr1kmA781_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000buh0zg515EA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000bugtt849220_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-08-06', '红棉大床套房', '套房', '代人预订', 135, 1, 88, 7, '["前台服务","安静程度","房间设施"]'::jsonb, '前台服务', '安静程度', '房间设施'),
('68027ea9e3c98b0941765c3b', '酒店年限有些久，设施相对有些老旧，楼下就是地铁口这点相对比较方便，服务人员态度一般，吃自助餐的时候还没吃完就要我签字房号。没有惊喜。花园瀑布餐厅算是一个打卡地非常出片。', '["https://dimg04.c-ctrip.com/images/0230z12000cawrf685F64_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000cax4hai9636_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000cawu33o6E33_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-10-01', '红棉大床套房', '套房', '家庭亲子', 84, 0, 15, 7, '["房间设施","交通便利性","餐饮设施"]'::jsonb, '房间设施', '交通便利性', '餐饮设施'),
('68027ea9e3c98b0941765c3c', '位置非常好，吃饭非常方便，酒店打卡的人很多，瀑布餐厅名不虚传，早餐服务很好，花园可以带小朋友喂鱼，博物馆也可以看一看。', '["https://dimg04.c-ctrip.com/images/0233912000cc2gwjqA94F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000cc2j8xc6A35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000cc2greoF3F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 59, 0, 8, 7, '["周边配套","餐饮设施","整体满意度"]'::jsonb, '周边配套', '餐饮设施', '整体满意度'),
('68027ea9e3c98b0941765c3d', '房间比较老，卫生间有补过?迹，但房间宽阔，价格实惠。', '["https://dimg04.c-ctrip.com/images/0236b12000coud33rE1A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000couau9qCBB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000couaz1gC65B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-06', '红棉大床套房', '套房', '家庭亲子', 26, 0, 6, 6, '["房间设施","价格合理性"]'::jsonb, '房间设施', '价格合理性', NULL),
('68027ea9e3c98b0941765c3e', '其他都不想说，除了床垫床垫床垫；第一次住酒店掀开床垫看，再看看官网价格！嗯 告辞！！早餐的环境还可以，菜品也就那样！', '["https://dimg04.c-ctrip.com/images/0233n12000cda81ve17C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000cda2gb088ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-11', '花园双床房', '双床房', '其他', 58, 0, 7, 5, '["房间设施","性价比","餐饮设施"]'::jsonb, '房间设施', '性价比', '餐饮设施'),
('68027ea9e3c98b0941765c3f', '环境服务都不错，就是以后办理入住的时候最好主动提醒一下房间是带早餐的，说明一下用餐地点和时间囖，不然我们自己都忘记了', '["https://dimg04.c-ctrip.com/images/0231s12000cc98ylm1659_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-06', '花园大床房', '大床房', '情侣出游', 58, 0, 1, 7, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68027ea9e3c98b0941765c40', '花园酒店的房间设施完善，舒适，一如既往的喜欢，酒店每个服务员的热情服务让我感到非常欣慰', '["https://dimg04.c-ctrip.com/images/0230c12000chmt9282512_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000chmfs0y90BC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-31', '花园双床房', '双床房', '商务出差', 43, 0, 7, 6, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68027ea9e3c98b0941765c41', '作为中国唯三的白金五星级酒店，花园酒店一直是广州的一个招牌，旅游出行很方便，环境非常不错，瀑布餐厅非常有名，服务也很到位，很欢喜，下次应该还会带娃来的，只可惜这次去的时候泳池在装修，没有游起来，算是开心旅程中的一点点遗憾吧', '["https://dimg04.c-ctrip.com/images/0232112000bu4c7he35D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-05', '红棉双床套房', '套房', '家庭亲子', 111, 0, 4, 8, '["整体满意度","交通便利性","公共设施"]'::jsonb, '整体满意度', '交通便利性', '公共设施'),
('68027eb6e3c98b0941765c42', '这次临时来广州办事，预定了放在收藏夹里很久的花园酒店，因为带了宝宝，想着要环境好一些，地方大一些，果然是不错的，宝宝每天和奶奶逛酒店很开心，我就和老公在外面办事情，一共续住了三次，总共住了八天，都不想换酒店，就一直在这续住，下次来还住这里????', '["https://dimg04.c-ctrip.com/images/0233g12000btv0r1g45B4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000btv0kr700F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000btv0oe94B08_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000btv0s7h8766_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000btv0sv0E919_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000btv0n1sB9A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000btv0ufr0067_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000btv0yf8C7B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000btv0rvuC484_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-04', '花园双床房', '双床房', '家庭亲子', 123, 1, 1, 7, '["整体满意度","房间设施","公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施'),
('68027eb6e3c98b0941765c43', '这次来广州，特地选择了代表着改革开放以后，“传说中的”第一批五星级酒店的几家酒店，走入酒店，那种开篇之作，厚重不浮夸的质感让人满意，环抱着的花园有典型岭南园林的痕迹，不能言表的高级感让酒店蕴含着神秘的气息。', '["https://dimg04.c-ctrip.com/images/0233w12000ca2czkl8C95_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000ca2d1762026_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000ca2cxkz1B03_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000ca2cxcuDE20_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000ca2cw939F61_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000ca2csj2B0ED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000ca2cys880F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000ca2ctblEF5A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000ca2cy0n0CC4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-29', '红棉大床套房', '套房', '家庭亲子', 103, 0, 10, 9, '["整体满意度","景观/朝向"]'::jsonb, '整体满意度', '景观/朝向', NULL),
('68027eb6e3c98b0941765c44', '酒店虽和我同龄，但维护保养的非常好，大气精致共存，特色餐厅也极具水准，难以想象，在1985年开业时这是怎样超前的存在！', '["https://dimg04.c-ctrip.com/images/0235l12000cbkcs7d2A67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000cbkgb1iEB61_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000cbkggwn5239_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000cbkjbht4C73_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000cbkjq1g1537_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-03', '红棉大床套房', '套房', '家庭亲子', 59, 0, 2, 8, '["整体满意度","餐饮设施","房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施'),
('68027eb6e3c98b0941765c45', '酒店很漂亮，不负白金酒店的称号，酒店在地铁5号线淘金站A口的边上，附近商城多，吃饭购物都很方便，酒店的服务也很好 ，入住的房间因网络有问题，而我们晚上有线上课，在和客房服务反应后，客户服务热心的帮我们升级了房间。早餐瀑布餐厅的服务员也都很热情。', '["https://dimg04.c-ctrip.com/images/0231b12000btrdw195238_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000btreuky00C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000btrhfoh4BA0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000btrf63t02B0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-04', '花园双床房', '双床房', '家庭亲子', 122, 1, 10, 9, '["交通便利性","周边配套","客房服务"]'::jsonb, '交通便利性', '周边配套', '客房服务'),
('68027eb6e3c98b0941765c46', '地段优越，环境好，交通便利，服务人员热情，餐厅的环境和食物的味道都很好，周边300米有点都德得和其他美食餐厅，值得入住。', '["https://dimg04.c-ctrip.com/images/0234r12000ccyxn1yAA0B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000ccyx6c64B11_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000ccyrqcxEB29_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-09', '城央绿意大床房', '大床房', '朋友出游', 60, 0, 10, 7, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68027eb6e3c98b0941765c47', '饭店历史悠久，风景极美，早餐非常丰盛！', '["https://dimg04.c-ctrip.com/images/0232v12000cr0ffg2BCA8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000cr0f01m70A4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-17', '花园大床房', '大床房', '商务出差', 19, 0, 10, 5, '["餐饮设施","景观/朝向","整体满意度"]'::jsonb, '餐饮设施', '景观/朝向', '整体满意度'),
('68027eb6e3c98b0941765c48', '主体建筑Y型，寓意“年轻和希望”的白金五星广州花园酒店，难得数十年来仍保持经典非凡，果然实至名归。
本次体验的是含行政礼遇的客房，除没有浴缸外，其他设施、卫生、环境、服务以及满溢岭南气息的后花园、故事感满满的大堂、餐厅和博物馆，都让人心悦诚服。
特别感谢锦鲤酒吧行政酒廊的服务员Carrie、Winnie、Mia、乐队和全体成员，还有送来精美点心的客房服务员??', '["https://dimg04.c-ctrip.com/images/0232v12000cd5gfew46B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000cd5mngp66A4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000cd5i482C811_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000cd5hcstC69D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-10', '花园双床房', '双床房', '其他', 181, 0, 35, 9, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027eb6e3c98b0941765c49', '第一次来广州，选择了久负盛名的花园酒店，，大厅和瀑布餐厅都很惊艳。特别要赞一下前台的Billy小哥哥，特别细心耐心，专业素质好，看到我一个人带孩子充分了解我的需求并且帮我规划了最优的方案。从长隆一身疲惫到了这里因为Billy感受到了宾至如归的感觉。', '["https://dimg04.c-ctrip.com/images/0236412000cz75nvzA5BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000cz6sxv62E2B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-19', '花园双床房', '双床房', '家庭亲子', 124, 2, 14, 9, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027eb6e3c98b0941765c4a', '非常不好的入住体验，一千多的价格，设施陈旧，只有个好看的酒店大堂，非常不值得推荐，建议大家多加几百推荐去珠江新城那几家，卫生状况极其差，只有浴缸，洗澡需要站立上去，感觉很不干净，而且带着老人家入住，爬不上去，大夏天只能将就一晚上，将就着住了一夜所谓的五星酒店，关了浴室门就没办法关卫生间的门，窗帘只有一层纱，而且很脏发黄，早上天一亮你就知道了，有一股发霉的老酒店味道，下次降到五百房价，都不推荐去住，差评内容还有很多很多', '["https://dimg04.c-ctrip.com/images/0233912000bsvr2n6C35B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000bsvtydl4A4B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-08-01', '花园双床房', '双床房', '商务出差', 210, 5, 1, 9, '["房间设施","卫生状况","性价比"]'::jsonb, '房间设施', '卫生状况', '性价比'),
('68027eb6e3c98b0941765c4b', '酒店38年了大堂还是金碧辉煌，38年前作为广州的五星级酒店还是硬件保养的不错，重新装修过的房间干净整洁，早餐比较中规中矩，总体还是非常满意。', '["https://dimg04.c-ctrip.com/images/0232d12000c8cv20wF5D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000c8cry0t14AB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000c8cpn3bD7CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000c8cy0d6D06C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000c8cxfknBC30_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000c8cz5pm9D88_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000c8csg7u6FD7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000c8cpw0o36C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000c8crs3u8227_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-24', '红棉大床套房', '套房', '其他', 70, 0, 42, 7, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('68027ec0e3c98b0941765c4c', '不愧是广花啊，服务环境都很满意，最关键的早餐是在瀑布餐厅吃，服务员小姐姐还很热情的帮忙拍照。吃早饭就可以去后面花园散步，瀑布下面有很多大锦鲤。', '["https://dimg04.c-ctrip.com/images/0232s12000c494aofB4EB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-12', '红棉双床套房', '套房', '家庭亲子', 71, 0, 2, 8, '["餐饮设施","整体满意度","公共设施"]'::jsonb, '餐饮设施', '整体满意度', '公共设施'),
('68027ec0e3c98b0941765c4d', '本次入住让我非常舒服感动，特别是Billy Deng 很热情,服务态度很好,细致周到,让我印象非常深刻!', '["https://dimg04.c-ctrip.com/images/0233612000cdvw1g32C75_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000cdw06pm7DB9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000cdw005u8C91_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-13', '花园行政大床套房', '套房', '商务出差', 52, 0, 172, 6, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68027ec0e3c98b0941765c4e', '酒店的地理位置超级无敌好，在淘金地铁站上来就看到了，我们早上到达酒店，因为未到两点暂时不能入住，就把行李寄存在大堂然后玩去了。晚上再回去办理入住，等候过程也很快。而且酒店很贴心，提早帮我们开了空调。想想在外面40多度的热浪中回到凉飕飕的房间，多舒服啊！重点是不用等房间降温！必须表扬！订酒店之前看评论，很纠结那个市政工程会不会噪音很大？我是神经质的睡眠，有点担心。酒店也很贴心，写了提醒字条在桌面上。幸好整个晚上到白天九点多我们出发时都很安静。 瀑布餐厅的早餐品种很多，工作人员的态度也非常好，环境一流，拍照打卡非常棒，不过要稍稍排一下队。要延迟退房跟客服说了一下就可以免费延迟到下午两点。说了好的方面，再提一下意见，为什么厕所跟浴房是同一扇推拉门呢？两个人同时使用的话，关哪边好？这个设计，不懂欣赏。', '["https://dimg04.c-ctrip.com/images/0232y12000bocj0b6A168_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000bocjrf0D013_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000boch9k6A0B4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000bocbgea3B79_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000bocilvqCAAE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000bocdo1iCF5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000bocemorA905_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000bocmc963FA2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000boce7nl32BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-17', '花园双床房', '双床房', '家庭亲子', 351, 0, 3, 9, '["交通便利性","前台服务","安静程度"]'::jsonb, '交通便利性', '前台服务', '安静程度'),
('68027ec0e3c98b0941765c4f', '酒店有着优秀服务的沉淀！地理位置优越，交通便利！花园酒店的精致花园使其名副其实！酒店大堂的设计依旧经典，极富艺术气息和美好寓意！房间到餐厅都非常用心，最爱在早餐看着瀑布，开启美好的广州之旅！羊羔公仔也是孩子爱不释手的布娃娃！', '["https://dimg04.c-ctrip.com/images/0232m12000c0dp47jE2D1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000c0dvyy688BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000c0dpamc53E8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000c0dwm8v7F09_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000c0ds68y4B53_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-26', '花园双床房', '双床房', '家庭亲子', 112, 0, 23, 8, '["整体满意度","交通便利性","餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施'),
('68027ec0e3c98b0941765c50', '外面看真的不错，大厅也很气派，看得出很有文化底蕴。迎宾以及服务员都很nice。就是房间有点小，酒店餐厅环境不错，但是早餐种类还是少了点。行程匆忙，也没来得及去酒店博物馆参观。去的时候泳池正在设备维护，没有去游泳很是遗憾。退房后有东西落酒店了，打电话过来询问，还帮忙快递，真的非常感谢，必须好评。', '["https://dimg04.c-ctrip.com/images/0234812000by7luqg6A1F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000by7f2c5A460_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000by7e6rq5FE5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-19', '花园双床房', '双床房', '家庭亲子', 147, 0, 5, 8, '["客房服务","餐饮设施","公共设施"]'::jsonb, '客房服务', '餐饮设施', '公共设施')
 ON CONFLICT (_id) DO NOTHING;
